var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"와아……. 진짜 저런 복장으로 다니는구나.","JPN":"わあ……マジであんな格好してるんだ。","ENG":"Woah… So they really do go around in that clown outfit.","TWN":"哇賽……竟然真的會有人穿那種衣服上街？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"야, 쟤네 보나마나 왕창 깨지겠지? 영상 찍고 있지?","JPN":"まあ、あいつらもどうせボコボコにやられるでしょ？　動画撮ってる？","ENG":"They're probably going to get their butt kicked, right? Are you recording this?","TWN":"喂，他們會死得很慘吧？你有拍下來嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그럼. 기껏 피난 안 가고 숨어 있었는데. 이건 건져야지.","JPN":"もちろん。このためにわざわざ避難しないで隠れてたし、ちゃんと撮っておかないと。","ENG":"Of course! This is exactly why we decided to hide instead of evacuate. I can't miss this.","TWN":"那當然！放棄逃難躲在這裡，當然要撈點好處！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"히히. 저 꼴로 싸우다 개박살 나면 넷튜브 웃음 토픽 감이겠다, 진짜.","JPN":"ひひひ。あんな格好で戦って、ボロクソに負けたらネットチューブのコメディ部門でトピックになりそうだな。","ENG":"Haha. They'll be a total laughing stock on NetTube if they lose wearing those outfits.","TWN":"嘿嘿，他們那樣盛裝打扮，到時候打輸的話，一定會成為網友的笑料！笑死！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흐앙……. 배에서 꼬르륵 소리 나…….","JPN":"ふえぇ……お腹がぐうぐう鳴ってる……","ENG":"Aw… My stomach is growling…","TWN":"嗚……我的肚子在咕嚕叫……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 우리 언제까지 여기서 폼 잡고 있어야 돼?","JPN":"副団長、私たちいつまでここで格好つけてなきゃいけないの？","ENG":"Deputy Commander. How long do we have to stand here like medieval cosplayers gone too far?","TWN":"副團長，我們要在這裡擺POSE到什麼時候？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경, 같은 기사단원으로서 그 평가는 그냥 넘어갈 수 없군요.","JPN":"アレン卿、同じ騎士団員としてその発言は見過ごせませんね。","ENG":"Dame Liv, as a fellow knight of the Order of Zodiac, I cannot simply ignore such irreverence from you.","TWN":"莉芙卿，同樣身為騎士團團員，我必須好好說說你。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희들이 비까지 맞으면서 이곳을 지키는 이유는 수배자의 목적지로 유력한 제프티 바이오테크의 본사로 통하는 길목이기 때문입니다.","JPN":"私たちが雨に打たれながらもここを守る理由は、\\nここが指名手配犯の目的地として有力視された\\nジェフティ・バイオテックの本社に通じる道だからです。","ENG":"The reason we're guarding this place, even in the rain, is because this leads to the corporate headquarters of Jehuty Biotech, a prime candidate for the wanted felon's destination.","TWN":"我們冒著雨守在這裡的原因，是因為這裡是通往傑夫堤生物科技總公司的必經之路，而那裡很可能就是通緝犯的目的地。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 그보다 중요한 이유가 있죠. 바로 불안에 떠는 시민들의 평안을 위해서입니다.","JPN":"しかし、それよりも重要な理由があります。それは、不安に怯えている市民のためです。","ENG":"But there is an even more important reason. Which is to restore peace for the civilians trembling in trepidation.","TWN":"但其實有另一個更重要的原因，就是保護市民免於恐懼害怕。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리가 경솔하게 행동할수록 시민들이 느끼는 방패의 무게도 가벼워집니다.","JPN":"私たちが軽率に行動するほど、市民たちが感じる盾の重さも軽くなります。","ENG":"The greater the levity of our actions, the less trustworthy the people will find us as their shield.","TWN":"我們越是草率行動，市民就會越沒安全感。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 그들이 이 소란 속에서도 안심할 수 있게 흔들림없는 자세를 유지해야 하는 것이죠.","JPN":"ですから、彼らがこの騒ぎの中でも安心できるように揺るぎない姿勢を維持しなければならないのです。","ENG":"Therefore, we must remain strong and steadfast if we are to reassure the public.","TWN":"所以我們才不能輕舉妄動，要一直保持姿勢，這樣在騷動中的市民才能感到安心。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 도시관리국의 요청을 받아들인 것이 수배자를 잡아 명예를 드높이기 위해서겠습니까?","JPN":"団長が都市管理局の要請を受け入れたのは、指名手配犯を捕まえて名誉を得るためでしょうか？","ENG":"Do you think the Commander accepted City Managements' request merely to build renown?","TWN":"難道你以為，團長之所以接受城市管理局的請求，目的是要抓住通緝犯提高聲望嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다! 자고로 기사의 명예란 기사도를 실천하는…….","JPN":"違います！　騎士の名誉というものは騎士道を実践する……","ENG":"Of course not! To an honorable knight, valor is more worthy than chivalry which-","TWN":"當然不是！自古以來，騎士的榮譽是來自於實踐騎士精神……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으아, 이러다 잔소리로 배가 부르겠어…….","JPN":"うわ、このままじゃ小言でお腹がいっぱいになっちゃう……","ENG":"Ugh, she'll drill a hole right through my ears with all that nagging…","TWN":"天啊，再說下去，我光聽你說教就飽啦……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그래서! 대체 리브 경은 언제나 철이 들 생각입니까? 그러니 한솔 경이나 에리어스 경은 고사하고 동생들한테까지 동생 취급을 받는 것 아닌가요?","JPN":"……アレン卿はいったいいつ大人になるつもりですか？\\nヤガミ卿やエスクェーデ卿はともかく、\\nそうだから弟たちにまで子ども扱いされるのではないですか？","ENG":"...and that brings me to this point! When will you ever grow up, Dame Liv? This is exactly why even your own younger siblings treat you like a child! Not to mention Sir Hansol and Dame Arius!","TWN":"……所以！莉芙卿，你到底什麼時候才要長大？我們先不說楊瀚卿或埃里奧斯卿，就連在妹妹們的面前，你也沒有一個姊姊的樣子！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아앗! 약한 구석 찌르는 건 비겁하다구?!","JPN":"ええーそんなストレートに突っ込まれると何も言い返せないじゃない！","ENG":"Ouch! Why do you have to stab me where it hurts? That's not fair!","TWN":"凹嗚！怎麼可以攻擊人家的致命傷？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경이 했던 기사 서약을 떠올려 보세요. 마음을 다잡는 데 도움이 될 겁니다.","JPN":"アレン卿が行った騎士の誓約を思い出してください。気持ちを引き締めるのに役立つでしょう。","ENG":"Remember the knight's oath you once made, Dame Liv. It will help you renew that noble spirit in you.","TWN":"莉芙卿，你想想你宣示過的騎士宣言，相信可以幫助你專心的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤, 어쩐다. <color=#ffd34c>조</color> 밖에 기억 안 나.","JPN":"へへッ、どうしよう。<color=#ffd34c>ゾ</color>しか思い出せないや。","ENG":"Hehe… The thing is… All I can remember is \\"<color=#ffd34c>Zo</color>\\".","TWN":"嘿嘿，我只記得<color=#ffd34c>十</color>而已…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>조디악 나이츠</color>로 시작합니다. 설마 유서 깊은 기사단명까지 잊으신 건 아니겠죠.","JPN":"<color=#ffd34c>ゾディアックナイツ</color>で始まります。まさか由緒ある騎士団の名まで忘れたわけではありませんよね？","ENG":"That's because we are the <color=#ffd34c>Zodiac Knights</color>. Please don't tell me you forgotten our own order's glorious name.","TWN":"開頭是<color=#ffd34c>十二宮騎士團</color>。你應該不會連歷史悠久的騎士團名稱都忘記吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장.","JPN":"副団長。","ENG":"Deputy Commander Lowell.","TWN":"副團長。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네. 단장님.","JPN":"はい、団長。","ENG":"Yes, Commander.","TWN":"是，團長。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"나타났다. 준비하도록.","JPN":"対象が現れた。準備を。","ENG":"She's here. Get ready.","TWN":"目標出現，準備！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잔여동력 3%. 비상기동 상태를 해제해 주십시오.</color>","JPN":"<color=#ffd34c>残余エネルギー3％。非常起動状態を解除してください。</color>","ENG":"<color=#ffd34c>Current remaining power is at 3%. Emergency maneuver mode highly recommended.</color>","TWN":"<color=#ffd34c>剩餘動能3%。請解除緊急啟動狀態。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"해제할 수 없겠군요. 이번에는 호락호락한 상대가 아닙니다.","JPN":"解除できません。今回は並みの相手ではありませんので。","ENG":"I'm afraid I can't do that right now. They're not going to be as easy as the others.","TWN":"看來是無法解除，這次的對手不好應付。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠 블루시프트의 단장, 에스테로사 드 슈발리에다.","JPN":"ゾディアックナイツ：ブルーシフトの団長、エステロサ・ド・シュヴァリエだ。","ENG":"I am Esterosa de Chevalier, the captain of the Zodiac Knights: Blue Shift.","TWN":"我是十二宮騎士團 藍移團長 艾斯特洛索。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대가 호라이즌인가?","JPN":"君がホライズンか？","ENG":"Are you Horizon?","TWN":"你就是地平線？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"긍정. 당신도 저를 방해하기 위해 기다리고 계셨습니까.","JPN":"肯定。あなたも私を邪魔するために待っていたのですか。","ENG":"Affirmative. Have you been waiting to stand in my way as well?","TWN":"正確，你也是一直等著要阻礙我嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 말투, 제가 과거에 조우한 적 있는 자를 떠오르게 하는군요.","JPN":"その話し方、私が過去に遭遇した者を思い出させます。","ENG":"Your manner of speech reminds me of someone I once encountered in the past.","TWN":"你說話的口吻，讓我想起之前遇到過的一個人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별난 사람을 만났나 보군.","JPN":"変わった者に出会ったようだな。","ENG":"How uncanny.","TWN":"看來是遇到怪人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"도시가 떠들썩하다. 도시관리국이 투입한 회심의 기갑 병기들도 여럿 파괴했다던가.","JPN":"都市が騒がしい。都市管理局が投入した会心の機甲兵器も多く破壊したと聞いたが。","ENG":"The entire city is awash with commotion. As I recall, you've even destroyed several armored systems City Management committed as the ace up their sleeves.","TWN":"城市現在鬧得滿城風雨。聽說城市管理局派出的多個機甲兵器也遭到破壞。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"타이탄들 상대로는 출력 조절이 고역이긴 하더군요.","JPN":"タイタンを相手に出力を調節するのはかなり苦戦しました。","ENG":"I must admit it was rather difficult restraining myself against those Titans.","TWN":"因為對手是那些泰坦，我還要一邊調整輸出。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아직 개선이 필요한 성능이었습니다. 양산형이니 편하게 개량 받겠지만요.","JPN":"まだ改善が必要な性能でした。量産型ですので、すぐに改良してもらえるとは思いますが。","ENG":"They could still use a few more upgrades. Which should be easy enough for mass-produced models.","TWN":"而且性能還有改善的空間，既然是量產型，應該可以接受改良吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 그대 한 명으로 인해, 수많은 시민들이 두려움에 떨고 있다는 사실도 알고 있나?","JPN":"それでは君は、君一人によって多くの市民が恐怖に震えているという事実も知っているのか？","ENG":"Then do you understand why countless civilians are trembling in fear because of you?","TWN":"那你知道，因為你一個人的緣故，讓許多的市民陷入恐慌之中嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"충분히 이해하고 있습니다.","JPN":"十分理解しています。","ENG":"I'm well aware.","TWN":"我非常清楚。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 당신들이 간섭하지 않는다면, 개인 대 개인으로 조용히 끝날 소란입니다.","JPN":"しかしあなたたちが干渉しなければ、個人対個人の話し合いで静かに解決できる騒動です。","ENG":"But all this commotion can end with just a single private confrontation if you do not intervene.","TWN":"但若不是因為你們的干涉，其實是可以一對一安靜地把事情解決掉。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그렇게는 안 되지! 그냥 빠이빠이 할 거면 뭐하러 쫄쫄 굶으면서 한참 기다렸냐구!","JPN":"そうはさせないよ！　このままバイバイなんて、こっちが腹ペコになるまでここで待機した意味がないでしょ！","ENG":"That won't do at all! We didn't wait this long starving just so we could say goodbye!","TWN":"那怎麼可以！現在離開的話，那我們幹嘛要忍著肚子餓等那麼久！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"경솔하게 뛰어들지 마세요, 리브 경. 저희는 다른 기사단원들에게 모범을 보여야 합니다.","JPN":"軽率な行動はやめてください、リブ卿。私たちは他の騎士団員に模範を見せなければなりません。","ENG":"Don't jump into combat so recklessly, Dame Liv. We must set good examples for the other knights of the order.","TWN":"莉芙卿，注意你的言行舉止，我們要成為其他騎士團團員的榜樣。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"조디악 나이츠. 데이터베이스에 존재하는 이름입니다.","JPN":"ゾディアックナイツ。データベースに存在する名前です。","ENG":"Zodiac Knights. That name does exist in the database.","TWN":"十二宮騎士團這個名字也有在資料庫裡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"개입 중단을 권고해 드려도, 당신들은 물러서지 않으시겠죠.","JPN":"介入中断を勧告しても、あなたたちは諦めないでしょう。","ENG":"Even if I urged you to suspend your intervention, I know you will not stand down.","TWN":"就算我勸你們停止干涉你們也不會聽吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"솔선수범하는 휴먼들일수록 타협을 어려워하니 말입니다.","JPN":"率先垂範するようなヒューマンほど、妥協が難しい傾向があります。","ENG":"The more exemplary humans tend to struggle with making compromises.","TWN":"畢竟越是以身作則的人類，就越難妥協。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"정답이다. 물러설 생각이었다면 처음부터 기사도를 따르지도 않았겠지.","JPN":"正解だ。引き下がるつもりならば初めから騎士道に従わなかっただろう。","ENG":"Precisely. We would not have become knights in the first place if we gave up so easily.","TWN":"正確，如果我們是可以輕易妥協的人，那當初也不會宣示騎士精神。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠! 대오를 갖춰라!","JPN":"ゾディアックナイツ！　隊列を整えろ！","ENG":"Zodiac Knights! Get into formation!","TWN":"十二宮騎士團！準備作戰！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"우리 역시 창칼로 우리가 옳다고 믿는 뜻을 관철하는 자들이다.","JPN":"我々も槍や剣を持ち、我々が正しいと信じた意思を貫く者たちだ。","ENG":"In the end, we too use our blades for the sake of what we believe to be right.","TWN":"我們會用刀槍證明我們貫徹的信念是對的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"결국 그대와 우리의 차이는 무엇을 위해 무기를 들었는지에 달려 있지.","JPN":"結局、君と我々の違いは何のために武器を持ったのかだけだ。","ENG":"The only thing that sets you apart from us is the purpose of carrying and using arms.","TWN":"其實你和我們的差別，就在於我們拿起武器的原因不同。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동의합니다. 의외로 솔직한 휴먼이시군요.","JPN":"同意します。意外と素直なヒューマンですね。","ENG":"I must concur. You are surprisingly honest for a human.","TWN":"同意，沒想到你是個直率的人類。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그럴 수밖에. 연설이나 설교는 부단장의 몫이니 말이다.","JPN":"そうするしかない。演説や説教は副団長の役目だ。","ENG":"I must be. Lectures and homilies are my deputy's to give.","TWN":"必須的。因為演講和說教是副團長的工作。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 나를 넘어서 가라.","JPN":"だからこれ以上進むのならば、私を越えて行きたまえ。","ENG":"So if you must go, go through me.","TWN":"所以越過我吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이 너머에, 그대가 진정으로 옳다고 믿는 길이 있다면.","JPN":"この向こうに、君が心から正しいと信じる道があるのなら。","ENG":"If the path you truly believe is right lies beyond here, that is.","TWN":"若你認為對的道路就在我的後方！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"광대라는 기록은 데이터베이스에서 삭제해야겠군요. 이래서 휴먼들의 평은 신뢰할 수가 없습니다.","JPN":"道化という記録はデータベースから\\n削除しなければなりませんね。これだからヒューマンの評価は信頼できません。","ENG":"I should delete your description of being a clown from my database. This is why I find human assessment of each other so unreliable.","TWN":"應該從資料庫刪除有關小丑的部分才對，因為這樣我才不相信人類的評語。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잔여동력 3%. 역장 활성화.</color>","JPN":"<color=#ffd34c>残余エネルギー3％。フォースシールド活性化。</color>","ENG":"<color=#ffd34c>Current remaining power is at 3%. Activating stasis field.</color>","TWN":"<color=#ffd34c>剩餘動能 3%。啟動力場。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제시하신 조건이 참에 해당하므로, 당신을 넘어서 가겠습니다.","JPN":"提示された条件が真に該当しますので、あなたを越えていきます。","ENG":"As the Boolean value to your if-then condition is True, I shall indeed go through you.","TWN":"你提出的條件非常好，那麼我會越過你。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};